{
  "query": "query AuctionFormOptions($category: String, $productName: String) { auctionFormOptions(category: $category, productName: $productName) }",
  "variables": {
    "category": "Coffee",
    "productName": "Export Coffee"
  }
}

{
  "query": "mutation EditAuction($id: ID!, $input: EditAuctionInput!) { editAuction(id: $id, input: $input) }",
  "variables": {
    "id": "{{auctionId}}",
    "input": {
      "title": "Postman Auction (Edited)",
      "auctionCategory": "Grains and Cereals",
      "productName": "Wheat",
      "commodityType": "white",
      "grade": "2",
      "quantity": "1200",
      "quantityUnit": "KG",
      "itemDescription": "Updated grains details from Postman",
      "auctionImageUrl": "{{auctionImageUrl}}"
    }
  }
}
